import React, { useEffect, useState, useCallback } from 'react';
import {
  Card,
  dispatchAppToast,
} from '@linm-soft-org/linm-web-common-components';
import {
  Title,
  Text,
  Tag,
  Spin,
  Statistic,
} from '@/components/common';
import { useAppDispatch } from '../../../store/hooks';
import { fpcService } from '../../../services/fpc/service';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import type { PlanVsActualDto } from '../../../services/fpc/types';
import styles from './PlanVsActualPage.module.css';

export default function PlanVsActualPage() {
  const dispatch = useAppDispatch();
  const [data, setData] = useState<PlanVsActualDto | null>(null);
  const [loading, setLoading] = useState(true);
  // TODO: replace native date inputs with utcToLocalInputValue / localInputToISOWithOffset
  const [dateRange, setDateRange] = useState<[string, string]>(() => {
    const now = new Date();
    const start = new Date(now.getFullYear(), now.getMonth(), 1);
    const end = new Date(now.getFullYear(), now.getMonth() + 1, 0);
    return [
      start.toISOString().slice(0, 10),
      end.toISOString().slice(0, 10),
    ];
  });

  const fetchData = useCallback(async () => {
    setLoading(true);
    try {
      const result = await fpcService.getPlanVsActual({
        periodStart: dateRange[0],
        periodEnd: dateRange[1],
      });
      setData(result);
    } catch (err) {
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(err, 'Không thể tải báo cáo kế hoạch so với thực tế'),
        type: 'error',
      });
    } finally {
      setLoading(false);
    }
  }, [dispatch, dateRange]);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  const varianceColor = (status: string) => {
    switch (status) {
      case 'Over': return '#cf1322';
      case 'Under': return '#3f8600';
      case 'OnTrack': return '#1677ff';
      default: return '#8c8c8c';
    }
  };

  const varianceLabel = (status: string) => {
    switch (status) {
      case 'Over': return 'Chi vượt';
      case 'Under': return 'Hụt thu';
      case 'OnTrack': return 'Đúng kế hoạch';
      default: return status;
    }
  };

  const formatMoney = (value: number) =>
    new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(value);

  return (
    <div className={styles.page}>
      <Title level={3}>Kế hoạch so với thực tế</Title>

      <Card className={styles.filterCard}>
        <div className={styles.filterBar}>
          <label className={styles.filterItem}>
            <Text>Từ ngày:</Text>
            <input
              type="date"
              value={dateRange[0]}
              onChange={(e) => setDateRange([e.target.value, dateRange[1]])}
              className={styles.dateInput}
            />
          </label>
          <label className={styles.filterItem}>
            <Text>Đến ngày:</Text>
            <input
              type="date"
              value={dateRange[1]}
              onChange={(e) => setDateRange([dateRange[0], e.target.value])}
              className={styles.dateInput}
            />
          </label>
        </div>
      </Card>

      {loading ? (
        <Spin size="large" style={{ display: 'block', margin: '80px auto' }} />
      ) : data ? (
        <>
          <div className={styles.statsGrid}>
            <Card>
              <Statistic
                title="Dòng tiền thu (KH)"
                value={data.totalPlanInflow}
                formatter={(v) => formatMoney(Number(v))}
                valueStyle={{ color: '#3f8600' }}
              />
            </Card>
            <Card>
              <Statistic
                title="Dòng tiền thu (TT)"
                value={data.totalActualInflow}
                formatter={(v) => formatMoney(Number(v))}
                valueStyle={{ color: '#3f8600' }}
              />
            </Card>
            <Card>
              <Statistic
                title="Dòng tiền chi (KH)"
                value={data.totalPlanOutflow}
                formatter={(v) => formatMoney(Number(v))}
                valueStyle={{ color: '#cf1322' }}
              />
            </Card>
            <Card>
              <Statistic
                title="Dòng tiền chi (TT)"
                value={data.totalActualOutflow}
                formatter={(v) => formatMoney(Number(v))}
                valueStyle={{ color: '#cf1322' }}
              />
            </Card>
          </div>

          <Card className={styles.tableCard}>
            <table className={styles.table}>
              <thead>
                <tr>
                  <th style={{ width: 220 }}>Danh mục</th>
                  <th style={{ width: 90 }}>Hướng</th>
                  <th className={styles.numCol}>Kế hoạch</th>
                  <th className={styles.numCol}>Thực tế</th>
                  <th className={styles.numCol}>Chênh lệch</th>
                  <th className={styles.numCol}>%</th>
                  <th style={{ width: 120 }}>Trạng thái</th>
                </tr>
              </thead>
              <tbody>
                {data.lines.map((line) => (
                  <tr key={line.categoryCode}>
                    <td>{line.categoryName}</td>
                    <td>
                      {line.direction === 'Inflow' ? (
                        <Tag color="#3f8600">Thu</Tag>
                      ) : (
                        <Tag color="#fa8c16">Chi</Tag>
                      )}
                    </td>
                    <td className={styles.numCol}>{formatMoney(line.planAmount)}</td>
                    <td className={styles.numCol}>{formatMoney(line.actualAmount)}</td>
                    <td className={styles.numCol}>
                      <Text type={line.variance >= 0 ? 'success' : 'danger'}>
                        {formatMoney(line.variance)}
                      </Text>
                    </td>
                    <td className={styles.numCol}>{line.variancePercent.toFixed(1)}%</td>
                    <td>
                      <Tag color={varianceColor(line.varianceStatus)}>
                        {varianceLabel(line.varianceStatus)}
                      </Tag>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </Card>
        </>
      ) : null}
    </div>
  );
}
